  const promoCode = metadata.promo ?? "";
  if (promoCode === "WELCOME10") {
    promoCents = Math.round(afterDiscount * 0.1);
  } else if (promoCode === "WELCOME20") {
    promoCents = Math.round(afterDiscount * 0.2);
  } else if (promoCode === "BLACKFRIDAY") {
