  if (paymentMethod === "crypto") riskScore += 40;
  if (daysSince < 1) riskScore += 35;
  if (items.length > 20) riskScore += 15;
  metadata.riskScore = String(riskScore);
  if (riskScore >= 80) {
    metadata.riskDecision = "block";
  } else if (riskScore >= 50) {
